export const globalSearchQueryPageDefault = 1;
export const globalSearchQueryLimitDefault = 20;

export const GlobalSearchQueryParams = zod.object({
  q: zod.coerce.string(),
  type: zod
    .enum([
      "dictionary",
      "diseases",
      "drugs",
      "books",
      "instruments",
      "tests",
      "slides",
      "notes",
      "normalRanges",
      "all",
    ])
    .default(globalSearchQueryTypeDefault),
  page: zod.coerce.number().default(globalSearchQueryPageDefault),
  limit: zod.coerce.number().default(globalSearchQueryLimitDefault),
});

